   165	using CasesByConfig = std::unordered_map<std::string, std::vector<CaseInput>>;
   166	
   167	CasesByConfig LoadCases(const std::string& jsonPath) {
   168	  CasesByConfig cases;
   169	  std::string content;
   170	  {
   171	    std::ifstream ifs(jsonPath);
   172	    if (!ifs.is_open()) {
   173	      throw std::runtime_error("Cannot open " + jsonPath);
   174	    }
   175	    std::stringstream buffer;
   176	    buffer << ifs.rdbuf();
   177	    content = buffer.str();
   178	  }
   179	
   180	  rapidjson::Document doc;
   181	  doc.Parse(content.c_str());
   182	  if (doc.HasParseError() || !doc.IsObject() || !doc.HasMember("cases") ||
   183	      !doc["cases"].IsArray()) {
   184	    throw std::runtime_error("Invalid testcases.json format");
   185	  }
   186	
   187	  for (auto& entry : doc["cases"].GetArray()) {
   188	    if (!entry.IsObject() || !entry.HasMember("input") ||
   189	        !entry["input"].IsString() || !entry.HasMember("expected") ||
   190	        !entry["expected"].IsObject()) {
   191	      continue;
   192	    }
   193	    const std::string input = entry["input"].GetString();
   194	    for (auto itr = entry["expected"].MemberBegin();
   195	         itr != entry["expected"].MemberEnd(); ++itr) {
   196	      if (!itr->value.IsString()) {
   197	        continue;
   198	      }
   199	      const std::string config = itr->name.GetString();
   200	      cases[config].push_back({input, itr->value.GetString()});
   201	    }
   202	  }
   203	  return cases;
   204	}
   205	
   206	TEST_F(CommandLineConvertTest, ConvertFromJson) {
   207	#ifdef BAZEL
   208	  const std::string casesPath =
   209	      runfiles_->Rlocation("_main/test/testcases/testcases.json");
   210	#else
   211	  const std::string casesPath = CMAKE_SOURCE_DIR "/test/testcases/testcases.json";
   212	#endif
   213	  const CasesByConfig cases = LoadCases(casesPath);
   214	
   215	  for (const auto& entry : cases) {
   216	    const std::string& config = entry.first;
   217	    const std::string inputFile = InputFile(config.c_str());
   218	    const std::string outputFile = OutputFile(config.c_str());
   219	
   220	    // Write inputs into a temp file (one per line).
   221	    {
   222	      std::ofstream ofs(inputFile, std::ios::binary);
   223	      ASSERT_TRUE(ofs.is_open()) << "Failed to open input file for writing: "
   224	                                 << inputFile;
   225	      for (const auto& item : entry.second) {
   226	        ofs << item.input << "\n";
   227	      }
   228	    }
   229	
   230	    ASSERT_EQ(0, system(TestCommand(config, inputFile, outputFile).c_str()));
   231	
   232	    // Read outputs and compare line by line.
   233	    std::ifstream ifs(outputFile, std::ios::binary);
   234	    ASSERT_TRUE(ifs.is_open());
   235	    std::string line;
   236	    size_t idx = 0;
   237	    while (std::getline(ifs, line)) {
   238	      if (!line.empty() && line.back() == '\r') {
   239	        line.pop_back(); // normalize Windows CRLF
   240	      }
   241	      ASSERT_LT(idx, entry.second.size());
   242	      EXPECT_EQ(entry.second[idx].expected, line)
   243	          << "config=" << config << " index=" << idx;
   244	      idx++;
   245	    }
   246	    EXPECT_EQ(idx, entry.second.size()) << "config=" << config;
   247	  }
   248	}
